#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int a[n], b[m];
        for (int i = 0; i < n; i++) scanf("%d", &a[i]);
        for (int i = 0; i < m; i++) scanf("%d", &b[i]);
        int sumA = 0, sumB = 0, sumSqA = 0, sumSqB = 0;
        for (int i = 0; i < n; i++) {
            sumA += a[i];
            sumSqA += a[i] * a[i];
        }
        for (int i = 0; i < m; i++) {
            sumB += b[i];
            sumSqB += b[i] * b[i];
        }
        if (sumA == sumB && sumSqA == sumSqB) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

